    // Initialize the system's core event management using FreeRTOS event groups
    event_group_ = xEventGroupCreate();
    if (event_group_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
        abort();
    }

    // Set up a periodic timer to generate clock tick events
    const esp_timer_create_args_t clock_timer_args = {
        .callback = [](void* arg) {
            Application* app = static_cast<Application*>(arg);
            xEventGroupSetBits(app->event_group_, MAIN_EVENT_CLOCK_TICK);
        },
        .name = "clock_tick",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK
    };

    esp_timer_err_t timer_err = esp_timer_create(&clock_timer_args, &clock_timer_handle_);
    if (timer_err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create clock timer: %s", esp_err_to_name(timer_err));
        abort();
    }

    // Configure the AEC mode based on configuration settings
    // Read AEC configuration from settings
