        } else if (strcmp(type->valuestring, "config") == 0) {
            auto aec_mode = cJSON_GetObjectItem(root, "aec_mode");
            if (aec_mode) {
                Schedule([this, aec_mode]() {
                    if (strcmp(aec_mode->valuestring, "off") == 0) {
                        SetAecMode(kAecOff);
                    } else if (strcmp(aec_mode->valuestring, "device") == 0) {
