            // This case handles the firmware upgrade process
            // Delay execution before starting the firmware upgrade process
            vTaskDelay(pdMS_TO_TICKS(1000));

            // Set device state to upgrading and display upgrade message
            display->SetStatus(Lang::Strings::UPGRADING);
            display->SetEmotion("download");
            display->SetChatMessage("system", Lang::Strings::PLEASE_WAIT);

