void McpServer::ParseMessage(const cJSON* json) {
    // Validate JSON-RPC 2.0 structure
    auto jsonrpc = cJSON_GetObjectItem(json, "jsonrpc");
    auto method = cJSON_GetObjectItem(json, "method");
    auto params = cJSON_GetObjectItem(json, "params");
    auto id = cJSON_GetObjectItem(json, "id");

    // Check if jsonrpc field exists and equals "2.0"
    if (!cJSON_IsString(jsonrpc) || strcmp(jsonrpc->valuestring, "2.0") != 0) {
        ESP_LOGE(TAG, "Invalid jsonrpc version");
        return;
    }

    // Check if method field exists
    if (!cJSON_IsString(method)) {
        ESP_LOGE(TAG, "Missing method field");
        ReplyError(-1, "Missing method field");
        return;
    }

    // Check if id field exists
    if (!id) {
        ESP_LOGE(TAG, "Missing id field");
        return;
    }

    int request_id = -1;
    if (cJSON_IsNumber(id)) {
        request_id = id->valueint;
    }

    std::string method_name = method->valuestring;

    // Handle different methods
    if (method_name == "initialize") {
        // Process initialize request
        cJSON* capabilities = cJSON_GetObjectItem(json, "capabilities");
        if (capabilities && cJSON_IsObject(capabilities)) {
            ParseCapabilities(capabilities);
        }

        // Create and send initialization response
        cJSON* response = cJSON_CreateObject();
        cJSON_AddStringToObject(response, "jsonrpc", "2.0");
        cJSON_AddNumberToObject(response, "id", request_id);

        cJSON* result = cJSON_CreateObject();
        cJSON_AddStringToObject(result, "protocolVersion", "2024-11-05");

        cJSON* server_info = cJSON_CreateObject();
        cJSON_AddStringToObject(server_info, "name", esp_app_desc->project_name);
        cJSON_AddStringToObject(server_info, "version", esp_app_desc->version);
        cJSON_AddItemToObject(result, "serverInfo", server_info);

        cJSON* capabilities_response = cJSON_CreateObject();
        cJSON_AddBoolToObject(capabilities_response, "tools", true);
        cJSON_AddBoolToObject(capabilities_response, "messages", true);
        cJSON_AddBoolToObject(capabilities_response, "prompts", true);
        cJSON_AddBoolToObject(capabilities_response, "resources", true);
        cJSON_AddBoolToObject(capabilities_response, "sessions", true);
        cJSON_AddItemToObject(result, "capabilities", capabilities_response);

        cJSON_AddItemToObject(response, "result", result);

        char* response_str = cJSON_PrintUnformatted(response);
        Application::GetInstance().SendMcpMessage(response_str);
        cJSON_Free(response_str);
        cJSON_Delete(response);

    } else if (method_name == "tools/list") {
        // Handle tools/list request
        std::string cursor = "";
        if (params && cJSON_IsObject(params)) {
            auto cursor_item = cJSON_GetObjectItem(params, "cursor");
            if (cJSON_IsString(cursor_item)) {
                cursor = cursor_item->valuestring;
            }
        }

        GetToolsList(request_id, cursor, false);

    } else if (method_name == "tools/call") {
        // Handle tools/call request
        if (!params || !cJSON_IsObject(params)) {
            ESP_LOGE(TAG, "tools/call: Invalid params");
            ReplyError(request_id, "Invalid params");
            return;
        }

        auto tool_name = cJSON_GetObjectItem(params, "toolName");
        auto tool_arguments = cJSON_GetObjectItem(params, "arguments");

        if (!tool_name || !cJSON_IsString(tool_name)) {
            ESP_LOGE(TAG, "tools/call: Missing or invalid toolName");
            ReplyError(request_id, "Missing or invalid toolName");
            return;
        }

        if (!tool_arguments || !cJSON_IsObject(tool_arguments)) {
            ESP_LOGE(TAG, "tools/call: Missing or invalid arguments");
            ReplyError(request_id, "Missing or invalid arguments");
            return;
        }

        DoToolCall(request_id, tool_name->valuestring, tool_arguments);

    } else {
        // Unknown method
        ESP_LOGE(TAG, "Unknown method: %s", method_name.c_str());
        ReplyError(request_id, "Method not supported: " + method_name);
    }
}

