void McpServer::GetToolsList(int id, const std::string& cursor, bool list_user_only_tools) {
    // Initialize pagination parameters
    const int kMaxToolsPerRequest = 100;
    int limit = kMaxToolsPerRequest;
    int offset = 0;

    // Validate cursor and parse offset if provided
    if (!cursor.empty()) {
        try {
            offset = std::stoi(cursor);
        } catch (const std::exception&) {
            // Invalid cursor, treat as no cursor
            offset = 0;
        }
    }

    // Retrieve the list of available tools from the MCP server context
    std::vector<const McpTool*> available_tools;

    for (const auto& tool : tools_) {
        // Filter tools based on user permissions
        if (list_user_only_tools) {
            // Include user-only tools
            if (tool->user_only()) {
                available_tools.push_back(tool);
            }
        } else {
            // Exclude user-only tools unless explicitly requested
            if (!tool->user_only()) {
                available_tools.push_back(tool);
            }
        }
    }

    // Apply cursor-based pagination to return a subset of tools
    int total_tools = available_tools.size();
    int start_index = offset;
    int end_index = std::min(start_index + limit, total_tools);

    // Create JSON response
    cJSON* result = cJSON_CreateObject();
    cJSON* tools_array = cJSON_CreateArray();

    // Add tools to the response
    for (int i = start_index; i < end_index; ++i) {
        const McpTool* tool = available_tools[i];

        // Check if tool can fit within payload size limits
        // For simplicity, we'll estimate the size based on name and description length
        size_t estimated_size = tool->name().length() + tool->description().length() + 100;
        if (estimated_size > 8192) { // Assuming 8KB limit for payload
            // Return error if tool size exceeds limit
            cJSON_Delete(result);
            ReplyError(id, "Tool '" + tool->name() + "' exceeds payload size limit");
            return;
        }

        cJSON* tool_json = cJSON_CreateObject();
        cJSON_AddStringToObject(tool_json, "name", tool->name().c_str());
        cJSON_AddStringToObject(tool_json, "description", tool->description().c_str());

        // Add parameters if any
        if (!tool->properties().empty()) {
            cJSON* parameters = cJSON_CreateObject();
            for (const auto& prop : tool->properties()) {
                cJSON* param = cJSON_CreateObject();
                cJSON_AddStringToObject(param, "type", 
                    prop.type() == kPropertyTypeString ? "string" :
                    prop.type() == kPropertyTypeInteger ? "integer" :
                    prop.type() == kPropertyTypeBoolean ? "boolean" : "unknown");

                if (prop.has_default_value()) {
                    switch (prop.type()) {
                        case kPropertyTypeString:
                            cJSON_AddStringToObject(param, "default", prop.value<std::string>().c_str());
                            break;
                        case kPropertyTypeInteger:
                            cJSON_AddNumberToObject(param, "default", prop.value<int>());
                            break;
                        case kPropertyTypeBoolean:
                            cJSON_AddBoolToObject(param, "default", prop.value<bool>());
                            break;
                    }
                }

                if (prop.min_value() != INT_MIN) {
                    cJSON_AddNumberToObject(param, "minimum", prop.min_value());
                }
                if (prop.max_value() != INT_MAX) {
                    cJSON_AddNumberToObject(param, "maximum", prop.max_value());
                }

                cJSON_AddItemToObject(parameters, prop.name().c_str(), param);
            }
            cJSON_AddItemToObject(tool_json, "parameters", parameters);
        }

        cJSON_AddItemToArray(tools_array, tool_json);
    }

    cJSON_AddItemToObject(result, "tools", tools_array);

    // Calculate next cursor
    int next_offset = end_index;
    if (next_offset < total_tools) {
        cJSON_AddStringToObject(result, "nextCursor", std::to_string(next_offset).c_str());
    }

    // Add total count
    cJSON_AddNumberToObject(result, "total", total_tools);

    // Serialize the response
    char* result_str = cJSON_PrintUnformatted(result);
    std::string response = result_str;
    cJSON_Free(result_str);
    cJSON_Delete(result);

    // Send the response
    ReplyResult(id, response);
}

