void McpServer::DoToolCall(int id, const std::string& tool_name, const cJSON* tool_arguments) {
    // Find the tool in the registered tools list
    McpTool* tool = nullptr;
    for (auto t : tools_) {
        if (t->name() == tool_name) {
            tool = t;
            break;
        }
    }

    // If tool not found, return error
    if (tool == nullptr) {
        ESP_LOGE(TAG, "Tool not found: %s", tool_name.c_str());
        ReplyError(id, "Tool not found: " + tool_name);
        return;
    }

    // Parse and validate arguments
    PropertyList properties;
    if (tool_arguments != nullptr) {
        // Convert cJSON object to PropertyList
        cJSON* arg = nullptr;
        cJSON_ArrayForEach(arg, tool_arguments) {
            if (cJSON_IsString(arg)) {
                properties[arg->string] = Property(arg->string, kPropertyTypeString, std::string(arg->valuestring));
            } else if (cJSON_IsNumber(arg)) {
                properties[arg->string] = Property(arg->string, kPropertyTypeInteger, static_cast<int>(arg->valuedouble));
            } else if (cJSON_IsBool(arg)) {
                properties[arg->string] = Property(arg->string, kPropertyTypeBoolean, arg->valueint != 0);
            } else if (cJSON_IsObject(arg)) {
                // Handle nested objects if needed
                std::string json_str = cJSON_PrintUnformatted(arg);
                properties[arg->string] = Property(arg->string, kPropertyTypeString, json_str);
            }
        }
    }

    // Validate required arguments
    for (const auto& expected_prop : tool->properties()) {
        if (expected_prop.required() && properties.find(expected_prop.name()) == properties.end()) {
            ESP_LOGE(TAG, "Missing required argument: %s for tool %s", expected_prop.name().c_str(), tool_name.c_str());
            ReplyError(id, "Missing required argument: " + expected_prop.name());
            return;
        }

        // Type checking
        if (properties.find(expected_prop.name()) != properties.end()) {
            const auto& actual_prop = properties.at(expected_prop.name());
            if (expected_prop.type() == kPropertyTypeInteger && actual_prop.type() != kPropertyTypeInteger) {
                ESP_LOGE(TAG, "Invalid type for argument %s: expected integer, got %d", expected_prop.name().c_str(), actual_prop.type());
                ReplyError(id, "Invalid type for argument " + expected_prop.name() + ": expected integer");
                return;
            } else if (expected_prop.type() == kPropertyTypeString && actual_prop.type() != kPropertyTypeString) {
                ESP_LOGE(TAG, "Invalid type for argument %s: expected string, got %d", expected_prop.name().c_str(), actual_prop.type());
                ReplyError(id, "Invalid type for argument " + expected_prop.name() + ": expected string");
                return;
            } else if (expected_prop.type() == kPropertyTypeBoolean && actual_prop.type() != kPropertyTypeBoolean) {
                ESP_LOGE(TAG, "Invalid type for argument %s: expected boolean, got %d", expected_prop.name().c_str(), actual_prop.type());
                ReplyError(id, "Invalid type for argument " + expected_prop.name() + ": expected boolean");
                return;
            }

            // Range checking for integers
            if (expected_prop.type() == kPropertyTypeInteger && 
                (actual_prop.value<int>() < expected_prop.min_value() || 
                 actual_prop.value<int>() > expected_prop.max_value())) {
                ESP_LOGE(TAG, "Value out of range for argument %s: %d not in [%d, %d]", 
                         expected_prop.name().c_str(), actual_prop.value<int>(), 
                         expected_prop.min_value(), expected_prop.max_value());
                ReplyError(id, "Value out of range for argument " + expected_prop.name() + 
                           ": " + std::to_string(actual_prop.value<int>()) + 
                           " not in [" + std::to_string(expected_prop.min_value()) + 
                           ", " + std::to_string(expected_prop.max_value()) + "]");
                return;
            }
        }
    }

    // Schedule tool execution on main application thread
    auto& app = Application::GetInstance();
    app.Schedule([this, id, tool, properties]() {
        try {
            // Execute the tool callback
            auto result = tool->callback()(properties);

            // Format and send result back
            std::string result_str;
            if (cJSON* json_result = std::get_if<cJSON*>(&result)) {
                if (json_result != nullptr) {
                    result_str = cJSON_PrintUnformatted(*json_result);
                } else {
                    result_str = "{}";
                }
            } else if (std::holds_alternative<bool>(result)) {
                result_str = std::get<bool>(result) ? "true" : "false";
            } else if (std::holds_alternative<std::string>(result)) {
                result_str = "\"" + std::get<std::string>(result) + "\"";
            } else {
                result_str = "{}";
            }

            std::string payload = "{\\"jsonrpc\\":\\"2.0\\",\\"id\\":" + std::to_string(id) + ",\\"result\\":" + result_str + "}";
            Application::GetInstance().SendMcpMessage(payload);
        } catch (const std::exception& e) {
            // Send error back to caller
            std::string error_msg = "Tool execution failed: " + std::string(e.what());
            ESP_LOGE(TAG, "%s", error_msg.c_str());
            ReplyError(id, error_msg);
        } catch (...) {
            // Send generic error back to caller
            std::string error_msg = "Tool execution failed with unknown error";
            ESP_LOGE(TAG, "%s", error_msg.c_str());
            ReplyError(id, error_msg);
        }
    });
}

