std::string Ota::GetActivationPayload() {
    // If no serial number is available, return empty JSON object
    if (!has_serial_number_) {
        return "{}";
    }

    // Create the JSON payload structure
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge string (using the activation challenge from the server)
    if (has_activation_challenge_) {
        cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());
    } else {
        // Fallback to empty string if no challenge available
        cJSON_AddStringToObject(root, "challenge", "");
    }

    // Generate HMAC-SHA256 signature using hardware-backed key
    #ifdef SOC_HMAC_SUPPORTED
    // Create message to sign: serial_number + challenge
    std::string message = serial_number_;
    if (has_activation_challenge_) {
        message += activation_challenge_;
    }

    // Prepare HMAC context
    esp_hmac_context_t hmac_ctx;
    esp_err_t err = esp_hmac_start(&hmac_ctx, ESP_HMAC_SHA256);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start HMAC context");
        cJSON_Delete(root);
        return "{}";
    }

    // Update with message
    err = esp_hmac_update(&hmac_ctx, (const uint8_t*)message.c_str(), message.length());
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to update HMAC");
        cJSON_Delete(root);
        return "{}";
    }

    // Get signature
    uint8_t signature[32]; // SHA256 produces 32 bytes
    err = esp_hmac_finish(&hmac_ctx, signature);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to finish HMAC");
        cJSON_Delete(root);
        return "{}";
    }

    // Convert signature to hex string for JSON
    std::string signature_hex;
    signature_hex.reserve(64);
    for (int i = 0; i < 32; i++) {
        char hex[3];
        snprintf(hex, sizeof(hex), "%02x", signature[i]);
        signature_hex += hex;
    }

    cJSON_AddStringToObject(root, "signature", signature_hex.c_str());
    #else
    // If HMAC is not supported, add empty signature
    cJSON_AddStringToObject(root, "signature", "");
    #endif

    // Convert to string
    char *json_string = cJSON_Print(root);
    std::string result = json_string ? json_string : "{}";

    // Clean up
    cJSON_Delete(root);
    if (json_string) {
        free(json_string);
    }

    return result;
}

