bool AudioService::ReadAudioData(std::vector<int16_t>& data, int sample_rate, int samples) {
    // Check if service is stopped
    if (service_stopped_) {
        return false;
    }

    // Enable input if not already enabled
    if (!codec_->input_enabled()) {
        codec_->EnableInput(true);
        // Give some time for codec to stabilize
        vTaskDelay(pdMS_TO_TICKS(10));
    }

    // Update last input time for power management
    last_input_time_ = std::chrono::steady_clock::now();

    // Get the actual number of samples available
    int actual_samples = samples;

    // Read raw audio data from codec
    std::vector<int16_t> raw_data(actual_samples * codec_->input_channels());

    // Read from the codec
    int read_samples = codec_->ReadAudioData(raw_data.data(), actual_samples);

    if (read_samples <= 0) {
        return false;
    }

    // Handle mono/stereo conversion
    if (codec_->input_channels() == 2 && codec_->input_channels() != 1) {
        // For stereo input, we typically want mono data
        // Take only the left channel (index 0) for mono processing
        std::vector<int16_t> mono_data(read_samples / 2);
        for (int i = 0; i < read_samples / 2; ++i) {
            mono_data[i] = raw_data[i * 2];  // Left channel
        }
        data = std::move(mono_data);
    } else {
        data = std::move(raw_data);
    }

    // Handle sample rate conversion if needed
    if (codec_->input_sample_rate() != sample_rate) {
        // Use the input resampler to convert sample rate
        int resampled_size = input_resampler_.GetOutputSamples(data.size());
        std::vector<int16_t> resampled_data(resampled_size);

        if (input_resampler_.Process(data.data(), data.size(), resampled_data.data())) {
            data = std::move(resampled_data);
        } else {
            // If resampling fails, return original data
            ESP_LOGW(TAG, "Failed to resample audio data");
        }
    }

    // Update statistics
    debug_statistics_.capture_count++;

    // For debugging purposes, log some information
    ESP_LOGD(TAG, "Captured %d samples at %d Hz", data.size(), sample_rate);

    return true;
}

