void AudioService::AudioInputTask() {
    ESP_LOGI(TAG, "Audio input task started");

    // Audio frame size configuration
    const int samples_per_frame = 160; // 10ms at 16kHz
    const int channels = codec_->input_channels();
    const int bytes_per_sample = sizeof(int16_t);
    const int frame_size_bytes = samples_per_frame * channels * bytes_per_sample;

    // Buffer for audio data
    std::vector<int16_t> audio_buffer(samples_per_frame * channels);

    while (!service_stopped_) {
        // Check if we should stop
        if (service_stopped_) {
            break;
        }

        // Read audio data from codec
        if (!ReadAudioData(audio_buffer, 16000, samples_per_frame)) {
            ESP_LOGW(TAG, "Failed to read audio data, retrying...");
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Get current system state from event group
        EventBits_t state = xEventGroupGetBits(event_group_);

        // Process based on system state
        if (state & AS_EVENT_AUDIO_TESTING_RUNNING) {
            // Audio testing mode - route to testing pipeline
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->frame_duration = OPUS_FRAME_DURATION_MS;
            packet->sample_rate = 16000;
            packet->payload.resize(audio_buffer.size() * sizeof(int16_t));
            memcpy(packet->payload.data(), audio_buffer.data(), packet->payload.size());

            std::lock_guard<std::mutex> lock(audio_queue_mutex_);
            if (audio_testing_queue_.size() < MAX_TESTING_PACKETS_IN_QUEUE) {
                audio_testing_queue_.push_back(std::move(packet));
                audio_queue_cv_.notify_all();
            }
        } 
        else if (state & AS_EVENT_WAKE_WORD_RUNNING) {
            // Wake word detection mode - feed to wake word processor
            if (wake_word_) {
                wake_word_->ProcessAudioFrame(audio_buffer);
            }
        } 
        else if (state & AS_EVENT_AUDIO_PROCESSOR_RUNNING) {
            // General audio processing mode - feed to audio processor
            if (audio_processor_) {
                audio_processor_->ProcessAudioFrame(audio_buffer);
            }
        } 
        else {
            // Default mode - feed to general processing
            if (audio_processor_) {
                audio_processor_->ProcessAudioFrame(audio_buffer);
            }
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(pdMS_TO_TICKS(1));
    }

    ESP_LOGW(TAG, "Audio input task stopped");
}

