void AudioService::AudioOutputTask() {
    while (true) {
        // Wait for the service to be stopped or for audio data to be available
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);
        audio_queue_cv_.wait(lock, [this]() {
            return service_stopped_ || !audio_playback_queue_.empty();
        });

        if (service_stopped_) {
            break;
        }

        // Process all available audio tasks in the playback queue
        while (!audio_playback_queue_.empty()) {
            auto task = std::move(audio_playback_queue_.front());
            audio_playback_queue_.pop_front();
            lock.unlock();

            // Enable audio output if not already enabled
            if (!codec_->output_enabled()) {
                esp_timer_stop(audio_power_timer_);
                esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
                codec_->EnableOutput(true);
            }

            // Send audio data to codec for output
            if (!codec_->OutputData(task->pcm)) {
                ESP_LOGE(TAG, "Failed to output audio data");
            }

            // Update last output time for power management
            last_output_time_ = std::chrono::steady_clock::now();

            // Update playback statistics
            debug_statistics_.output_count++;

            // Record timestamp for server-side AEC if needed
            if (CONFIG_SERVER_SIDE_AEC && task->timestamp != 0) {
                // Store timestamp for AEC processing
                if (timestamp_queue_.size() < MAX_TIMESTAMPS_IN_QUEUE) {
                    timestamp_queue_.push_back(task->timestamp);
                } else {
                    ESP_LOGW(TAG, "Timestamp queue is full, dropping timestamp");
                }
            }

            lock.lock();
        }

        // Notify other threads that we've processed some data
        audio_queue_cv_.notify_all();
    }

    ESP_LOGW(TAG, "Audio output task stopped");
}

