void AudioService::OpusCodecTask() {
    while (true) {
        // Wait for events or timeout
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
            AS_EVENT_AUDIO_TESTING_RUNNING | AS_EVENT_WAKE_WORD_RUNNING | AS_EVENT_AUDIO_PROCESSOR_RUNNING,
            pdFALSE, pdFALSE, portMAX_DELAY);

        if (service_stopped_) {
            break;
        }

        // Process encode queue (PCM -> Opus)
        {
            std::unique_lock<std::mutex> lock(audio_queue_mutex_);

            // Process encode queue
            while (!audio_encode_queue_.empty()) {
                auto task = std::move(audio_encode_queue_.front());
                audio_encode_queue_.pop_front();

                // Check if we have enough data for one frame
                if (task->pcm.empty()) {
                    continue;
                }

                // Encode PCM to Opus
                std::vector<uint8_t> encoded_data;
                int encoded_size = opus_encoder_->Encode(task->pcm.data(), task->pcm.size(), encoded_data);

                if (encoded_size > 0) {
                    // Create packet for sending
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->payload = std::move(encoded_data);
                    packet->sample_rate = opus_encoder_->sample_rate();
                    packet->frame_duration = opus_encoder_->duration_ms();

                    // Add to send queue if it's for sending
                    if (task->type == kAudioTaskTypeEncodeToSendQueue) {
                        // Ensure we don't exceed queue limits
                        if (audio_send_queue_.size() < MAX_SEND_PACKETS_IN_QUEUE) {
                            audio_send_queue_.push_back(std::move(packet));
                        } else {
                            ESP_LOGW(TAG, "Send queue is full, dropping packet");
                        }
                    }
                }

                // Notify that we've processed a task
                audio_queue_cv_.notify_all();
            }
        }

        // Process decode queue (Opus -> PCM)
        {
            std::unique_lock<std::mutex> lock(audio_queue_mutex_);

            // Process decode queue
            while (!audio_decode_queue_.empty()) {
                auto packet = std::move(audio_decode_queue_.front());
                audio_decode_queue_.pop_front();

                // Decode Opus to PCM
                std::vector<int16_t> decoded_data;
                int decoded_size = opus_decoder_->Decode(packet->payload.data(), packet->payload.size(), decoded_data);

                if (decoded_size > 0) {
                    // Apply sample rate conversion if needed
                    if (codec_->output_sample_rate() != opus_decoder_->sample_rate()) {
                        auto resampled_data = std::vector<int16_t>(output_resampler_.GetOutputSamples(decoded_data.size()));
                        output_resampler_.Process(decoded_data.data(), decoded_data.size(), resampled_data.data());
                        decoded_data = std::move(resampled_data);
                    }

                    // Add to playback queue
                    auto playback_task = std::make_unique<AudioTask>();
                    playback_task->pcm = std::move(decoded_data);
                    playback_task->timestamp = packet->timestamp;

                    // Ensure we don't exceed playback queue limits
                    if (audio_playback_queue_.size() < MAX_PLAYBACK_TASKS_IN_QUEUE) {
                        audio_playback_queue_.push_back(std::move(playback_task));
                    } else {
                        ESP_LOGW(TAG, "Playback queue is full, dropping audio data");
                    }
                }

                // Notify that we've processed a packet
                audio_queue_cv_.notify_all();
            }
        }

        // Process testing queue
        {
            std::unique_lock<std::mutex> lock(audio_queue_mutex_);

            // Process testing queue
            while (!audio_testing_queue_.empty()) {
                auto task = std::move(audio_testing_queue_.front());
                audio_testing_queue_.pop_front();

                // Encode PCM to Opus for testing
                std::vector<uint8_t> encoded_data;
                int encoded_size = opus_encoder_->Encode(task->pcm.data(), task->pcm.size(), encoded_data);

                if (encoded_size > 0) {
                    // Create packet for testing
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->payload = std::move(encoded_data);
                    packet->sample_rate = opus_encoder_->sample_rate();
                    packet->frame_duration = opus_encoder_->duration_ms();

                    // Add to testing queue
                    if (audio_testing_queue_.size() < MAX_TESTING_PACKETS_IN_QUEUE) {
                        audio_testing_queue_.push_back(std::move(packet));
                    } else {
                        ESP_LOGW(TAG, "Testing queue is full, dropping packet");
                    }
                }

                // Notify that we've processed a test task
                audio_queue_cv_.notify_all();
            }
        }

        // Check if we should process more data
        if (audio_encode_queue_.empty() && audio_decode_queue_.empty() && audio_testing_queue_.empty()) {
            // Small delay to prevent busy waiting
            vTaskDelay(pdMS_TO_TICKS(1));
        }
    }

    ESP_LOGW(TAG, "Opus codec task stopped");
}

