void AudioService::PushTaskToEncodeQueue(AudioTaskType type, std::vector<int16_t>&& pcm) {
    // Validate the audio task type - only allow encoding task types
    if (type != kAudioTaskTypeEncodeToSendQueue && 
        type != kAudioTaskTypeEncodeToTestingQueue) {
        ESP_LOGE(TAG, "Invalid audio task type for encode queue");
        return;
    }

    // Create audio task
    auto task = std::make_unique<AudioTask>();
    task->type = type;
    task->pcm = std::move(pcm);

    // Handle timestamp for EncodeToSendQueue tasks
    if (type == kAudioTaskTypeEncodeToSendQueue) {
        std::lock_guard<std::mutex> lock(audio_queue_mutex_);
        // Get timestamp from the timestamp queue if available
        if (!timestamp_queue_.empty()) {
            task->timestamp = timestamp_queue_.front();
            timestamp_queue_.pop_front();
        } else {
            // Generate timestamp if none available
            task->timestamp = std::chrono::duration_cast<std::chrono::milliseconds>(
                std::chrono::steady_clock::now().time_since_epoch()).count();
        }
    }

    // Wait for space in the encode queue if it's full
    std::unique_lock<std::mutex> lock(audio_queue_mutex_);
    audio_queue_cv_.wait(lock, [this]() {
        return audio_encode_queue_.size() < MAX_ENCODE_TASKS_IN_QUEUE;
    });

    // Add the task to the encode queue
    audio_encode_queue_.push_back(std::move(task));
    audio_queue_cv_.notify_all();
}

