            ESP_LOGE(TAG, "Wake word detection cannot be enabled: wake word system not initialized");
            return;
        }

        // Start the wake word detection process
        if (wake_word_) {
            wake_word_->Start();
        }

        // Set the event flag indicating wake word detection is active
        xEventGroupSetBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    } else {
        // Stop the wake word detection process
        if (wake_word_) {
            wake_word_->Stop();
        }

        // Clear the event flag indicating wake word detection is inactive
        xEventGroupClearBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    }
}

