    // Initialize appropriate wake word engine based on platform and model types
    #if CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4
        // For ESP32-S3 and ESP32-P4, prefer AFE-based wake word detection
        if (has_custom_model) {
