            wake_word_ = std::make_unique<CustomWakeWord>();
            ESP_LOGI(TAG, "Using Custom Wake Word Engine");
        } else {
            // Use AFE-based wake word engine
            wake_word_ = std::make_unique<AfeWakeWord>();
            ESP_LOGI(TAG, "Using AFE Wake Word Engine");
        }
    #else
        // For other platforms, use ESP-based wake word detection
        if (has_custom_model) {
            // Use custom wake word engine
            wake_word_ = std::make_unique<CustomWakeWord>();
            ESP_LOGI(TAG, "Using Custom Wake Word Engine");
        } else {
            // Use ESP-based wake word engine
            wake_word_ = std::make_unique<EspWakeWord>();
            ESP_LOGI(TAG, "Using ESP Wake Word Engine");
        }
    #endif

    // Register callback for wake word detection events
    if (wake_word_) {
        wake_word_->OnWakeWordDetected([this](const std::string& wake_word) {
            if (callbacks_.on_wake_word_detected) {
                callbacks_.on_wake_word_detected(wake_word);
            }
        });

        // Initialize the wake word engine with current codec and models
        if (!wake_word_->Initialize(codec_, models_list_)) {
            ESP_LOGE(TAG, "Failed to initialize wake word engine");
            wake_word_.reset();
            return;
        }

        wake_word_initialized_ = true;
        ESP_LOGI(TAG, "Wake word engine initialized successfully");
    }
