void AfeWakeWord::AudioDetectionTask() {
    ESP_LOGI(TAG, "Audio detection task started");

    while (true) {
        // Wait for detection to be started
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                               DETECTION_RUNNING_EVENT, 
                                               pdFALSE, 
                                               pdFALSE, 
                                               portMAX_DELAY);

        if (bits & DETECTION_RUNNING_EVENT) {
            // Check if we have valid AFE data
            if (afe_data_ == nullptr) {
                vTaskDelay(10 / portTICK_PERIOD_MS);
                continue;
            }

            // Get audio data from codec
            std::vector<int16_t> audio_buffer(GetFeedSize());
            if (codec_ && codec_->Read(audio_buffer.data(), audio_buffer.size()) > 0) {
                // Feed data to AFE
                afe_iface_->feed(afe_data_, audio_buffer.data());

                // Check for wake word detection
                int result = afe_iface_->detect(afe_data_);

                if (result >= 0 && result < (int)wake_words_.size()) {
                    // Wake word detected
                    ESP_LOGI(TAG, "Wake word detected: %s", wake_words_[result].c_str());

                    // Stop detection
                    Stop();

                    // Store the audio data for the wake word
                    StoreWakeWordData(audio_buffer.data(), audio_buffer.size());

                    // Trigger callback
                    if (wake_word_detected_callback_) {
                        wake_word_detected_callback_(wake_words_[result]);
                    }

                    // Set last detected wake word
                    last_detected_wake_word_ = wake_words_[result];
                }
            }
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(1 / portTICK_PERIOD_MS);
    }
}

