void AfeWakeWord::EncodeWakeWordData() {
    // Create a new task for encoding wake word data
    wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(
        4096 * sizeof(StackType_t), MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);

    if (wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate stack for wake word encode task");
        return;
    }

    wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(
        sizeof(StaticTask_t), MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);

    if (wake_word_encode_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return;
    }

    // Create the encoding task
    wake_word_encode_task_ = xTaskCreateStatic([](void* arg) {
        auto this_ = (AfeWakeWord*)arg;
        this_->EncodeWakeWordDataTask();
    }, "wake_word_encode", 4096, this, 3, 
    wake_word_encode_task_stack_, wake_word_encode_task_buffer_);

    if (wake_word_encode_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
        return;
    }
}

void AfeWakeWord::EncodeWakeWordDataTask() {
    // Initialize Opus encoder with low complexity settings
    OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
    if (encoder == nullptr) {
        ESP_LOGE(TAG, "Failed to create Opus encoder");
        vTaskDelete(NULL);
        return;
    }

    // Set encoder to low complexity mode for fast encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000)); // 24 kbps

    // Process all stored PCM data
    std::vector<int16_t> pcm_data;
    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        // Copy all PCM data to process
        for (const auto& packet : wake_word_pcm_) {
            pcm_data.insert(pcm_data.end(), packet.begin(), packet.end());
        }
        // Clear the PCM data after copying
        wake_word_pcm_.clear();
    }

    if (pcm_data.empty()) {
        opus_encoder_destroy(encoder);
        vTaskDelete(NULL);
        return;
    }

    // Encode PCM data to Opus
    std::vector<uint8_t> opus_packets;
    opus_int32 max_packet_size = 1024; // Maximum Opus packet size
    opus_packets.resize(max_packet_size);

    // Process data in chunks to avoid memory issues
    const size_t chunk_size = 512; // 32ms of 16kHz audio
    size_t total_samples = pcm_data.size();
    size_t processed_samples = 0;

    while (processed_samples < total_samples) {
        size_t samples_to_process = std::min(chunk_size, total_samples - processed_samples);
        int opus_frame_size = opus_encode(encoder, 
                                         &pcm_data[processed_samples], 
                                         samples_to_process, 
                                         &opus_packets[0], 
                                         max_packet_size);

        if (opus_frame_size > 0) {
            // Add successfully encoded packet to our output
            std::vector<uint8_t> packet(opus_packets.begin(), 
                                      opus_packets.begin() + opus_frame_size);

            std::lock_guard<std::mutex> lock(wake_word_mutex_);
            wake_word_opus_.push_back(std::move(packet));
        }

        processed_samples += samples_to_process;
    }

    // Clean up
    opus_encoder_destroy(encoder);

    // Signal completion via condition variable
    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_cv_.notify_all();
    }

    vTaskDelete(NULL);
}

