void CustomWakeWord::ParseWakenetModelConfig() {
    // Load the index.json file from assets
    const char* json_data = assets_get_data("index.json");
    if (json_data == nullptr) {
        ESP_LOGE(TAG, "Failed to load index.json file");
        return;
    }

    // Parse JSON data
    cJSON* json_root = cJSON_Parse(json_data);
    if (json_root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json: %s", cJSON_GetErrorPtr());
        return;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(json_root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = language_item->valuestring;
    } else {
        language_ = "cn"; // Default language
        ESP_LOGW(TAG, "Language not found in config, using default: cn");
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(json_root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valuedouble;
    } else {
        duration_ = 3.0; // Default duration
        ESP_LOGW(TAG, "Duration not found in config, using default: 3.0");
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(json_root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = threshold_item->valuedouble;
    } else {
        threshold_ = 0.8; // Default threshold
        ESP_LOGW(TAG, "Threshold not found in config, using default: 0.8");
    }

    // Extract commands
    cJSON* commands_item = cJSON_GetObjectItem(json_root, "commands");
    if (commands_item != nullptr && cJSON_IsArray(commands_item)) {
        int num_commands = cJSON_GetArraySize(commands_item);
        for (int i = 0; i < num_commands; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_item, i);
            if (command_obj == nullptr) continue;

            // Extract command name
            cJSON* command_name = cJSON_GetObjectItem(command_obj, "command");
            if (command_name == nullptr || !cJSON_IsString(command_name)) {
                ESP_LOGW(TAG, "Invalid command name in config at index %d", i);
                continue;
            }

            // Extract display text
            cJSON* display_text = cJSON_GetObjectItem(command_obj, "display");
            if (display_text == nullptr || !cJSON_IsString(display_text)) {
                ESP_LOGW(TAG, "Invalid display text in config at index %d", i);
                continue;
            }

            // Extract action type
            cJSON* action_type = cJSON_GetObjectItem(command_obj, "action");
            if (action_type == nullptr || !cJSON_IsString(action_type)) {
                ESP_LOGW(TAG, "Invalid action type in config at index %d", i);
                continue;
            }

            // Add command to list
            commands_.push_back({
                std::string(command_name->valuestring),
                std::string(display_text->valuestring),
                std::string(action_type->valuestring)
            });

            // Log the parsed command
            ESP_LOGI(TAG, "Parsed command: command='%s', display='%s', action='%s'", 
                     command_name->valuestring, display_text->valuestring, action_type->valuestring);
        }
    } else {
        ESP_LOGW(TAG, "Commands array not found in config");
    }

    // Clean up JSON parser
    cJSON_Delete(json_root);
}

