void CustomWakeWord::Feed(const std::vector<int16_t>& data) {
    // Check if processing is enabled
    if (!running_) {
        return;
    }

    // Handle mono/stereo conversion - extract left channel if stereo
    std::vector<int16_t> processed_data = data;
    if (codec_ != nullptr && codec_->GetChannels() == 2) {
        // For stereo input, extract left channel (assuming interleaved format)
        std::vector<int16_t> left_channel;
        left_channel.reserve(data.size() / 2);
        for (size_t i = 0; i < data.size(); i += 2) {
            left_channel.push_back(data[i]);
        }
        processed_data = std::move(left_channel);
    }

    // Store the processed audio data
    StoreWakeWordData(processed_data);

    // Run multinet model inference on buffered audio data
    if (multinet_model_data_ != nullptr && multinet_ != nullptr) {
        // Get the required chunk size for processing
        size_t chunk_size = multinet_->get_samp_chunksize(multinet_model_data_);

        // Process only when we have enough data
        if (wake_word_pcm_.size() >= chunk_size) {
            // Prepare input data for multinet
            std::vector<int16_t> input_data;
            input_data.reserve(chunk_size);

            // Take the most recent chunk_size samples
            auto it = wake_word_pcm_.rbegin();
            for (size_t i = 0; i < chunk_size && it != wake_word_pcm_.rend(); ++i, ++it) {
                input_data.insert(input_data.end(), it->begin(), it->end());
            }

            // Ensure we have exactly chunk_size samples
            if (input_data.size() == chunk_size) {
                // Run the multinet detection
                int result = multinet_->detect(multinet_model_data_, input_data.data());

                // Check if wake word was detected
                if (result > 0 && result <= static_cast<int>(commands_.size())) {
                    // Trigger callback with the identified wake word
                    if (wake_word_detected_callback_) {
                        wake_word_detected_callback_(commands_[result - 1].command);
                    }

                    // Stop further processing until reactivated
                    running_ = false;
                }
            }
        }
    }
}

