void CustomWakeWord::EncodeWakeWordData() {
    // Allocate memory for the encoding task if not already allocated
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = static_cast<StackType_t*>(
            heap_caps_malloc(CONFIG_CUSTOM_WAKE_WORD_ENCODE_TASK_STACK_SIZE * sizeof(StackType_t), 
                           MALLOC_CAP_8BIT | MALLOC_CAP_DMA));
        if (wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate wake word encode task stack");
            return;
        }
    }

    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = static_cast<StaticTask_t*>(
            heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_8BIT));
        if (wake_word_encode_task_buffer_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate wake word encode task buffer");
            return;
        }
    }

    // Create and start the encoding task
    BaseType_t ret = xTaskCreateStatic(
        [](void* arg) {
            CustomWakeWord* self = static_cast<CustomWakeWord*>(arg);

            // Initialize Opus encoder
            OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
            if (encoder == nullptr) {
                ESP_LOGE(TAG, "Failed to create Opus encoder");
                return;
            }

            // Set encoder parameters for low complexity
            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));  // Low complexity
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000)); // 24 kbps bitrate

            // Process each PCM segment
            std::unique_lock<std::mutex> lock(self->wake_word_mutex_);
            std::vector<int16_t> pcm_buffer;
            std::vector<uint8_t> opus_buffer(1024); // Initial buffer size

            // Copy all stored PCM data
            for (const auto& segment : self->wake_word_pcm_) {
                pcm_buffer.insert(pcm_buffer.end(), segment.begin(), segment.end());
            }

            // Clear the PCM storage after copying
            self->wake_word_pcm_.clear();
            lock.unlock();

            // Encode PCM data to Opus
            if (!pcm_buffer.empty()) {
                int frame_size = 160; // 10ms at 16kHz
                int num_frames = pcm_buffer.size() / frame_size;

                for (int i = 0; i < num_frames; i++) {
                    int16_t* frame_data = pcm_buffer.data() + (i * frame_size);
                    int opus_frame_size = opus_encode(encoder, frame_data, frame_size, 
                                                    opus_buffer.data(), opus_buffer.size());

                    if (opus_frame_size > 0) {
                        std::vector<uint8_t> encoded_data(opus_buffer.begin(), 
                                                        opus_buffer.begin() + opus_frame_size);

                        std::lock_guard<std::mutex> lock(self->wake_word_mutex_);
                        self->wake_word_opus_.push_back(encoded_data);
                        self->wake_word_cv_.notify_one();
                    }
                }
            }

            // Add termination marker (0xFF)
            std::vector<uint8_t> termination_marker = {0xFF};
            std::lock_guard<std::mutex> lock(self->wake_word_mutex_);
            self->wake_word_opus_.push_back(termination_marker);
            self->wake_word_cv_.notify_one();

            // Clean up
            opus_encoder_destroy(encoder);

            // Signal that encoding is complete
            ESP_LOGI(TAG, "Wake word encoding completed");
        },
        "wake_word_encode",
        CONFIG_CUSTOM_WAKE_WORD_ENCODE_TASK_STACK_SIZE,
        this,
        CONFIG_CUSTOM_WAKE_WORD_ENCODE_TASK_PRIORITY,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (ret != pdPASS) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
    }
}

