std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float> &samples)
{
    std::vector<float> probabilities;

    // Process each sample in the input vector
    for (size_t i = 0; i < samples.size(); ++i)
    {
        // Feed the current sample to both frequency detectors
        mark_detector_->ProcessSample(samples[i]);
        space_detector_->ProcessSample(samples[i]);

        // When we have enough samples for a complete window
        if ((i + 1) % input_buffer_size_ == 0)
        {
            // Get amplitude from both detectors
            float mark_amplitude = mark_detector_->GetAmplitude();
            float space_amplitude = space_detector_->GetAmplitude();

            // Calculate probability of mark tone presence
            // Simple approach: compare amplitudes to determine which tone is stronger
            float probability = 0.0f;
            if (mark_amplitude > space_amplitude)
            {
                // Mark tone is more prominent
                probability = mark_amplitude / (mark_amplitude + space_amplitude + 1e-8f);
            }
            else
            {
                // Space tone is more prominent or they're similar
                probability = 0.0f;
            }

            probabilities.push_back(probability);
        }
    }

    return probabilities;
}

