Esp32Camera::Esp32Camera(const esp_video_init_config_t& config) {
    video_fd_ = -1;
    streaming_on_ = false;
    sensor_format_ = 0;
    sensor_width_ = 0;
    sensor_height_ = 0;

    // Initialize the camera hardware based on the provided configuration
    esp_video_device_t* video_dev = nullptr;
    esp_err_t err = esp_video_init(&config, &video_dev);
    if (err != ESP_OK || video_dev == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize video device: %s", esp_err_to_name(err));
        return;
    }

    // Open the video device
    char dev_path[16];
    snprintf(dev_path, sizeof(dev_path), "/dev/video%d", video_dev->dev_id);
    video_fd_ = open(dev_path, O_RDWR);
    if (video_fd_ < 0) {
        ESP_LOGE(TAG, "Failed to open video device %s: %s", dev_path, strerror(errno));
        esp_video_deinit();
        return;
    }

    // Validate device capabilities using V4L2 IOCTL commands
    struct v4l2_capability cap = {};
    if (ioctl(video_fd_, VIDIOC_QUERYCAP, &cap) < 0) {
        ESP_LOGE(TAG, "Failed to query video device capabilities: %s", strerror(errno));
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
        ESP_LOGE(TAG, "Video device does not support video capture");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    // Set initial pixel format and resolution for video capture
    struct v4l2_format fmt = {};
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(video_fd_, VIDIOC_G_FMT, &fmt) < 0) {
        ESP_LOGE(TAG, "Failed to get video format: %s", strerror(errno));
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    // Store sensor information
    sensor_format_ = fmt.fmt.pix.pixelformat;
    sensor_width_ = fmt.fmt.pix.width;
    sensor_height_ = fmt.fmt.pix.height;

    CAM_PRINT_FOURCC(sensor_format_);

    // Check if the requested format is supported
    if (fmt.fmt.pix.pixelformat != config.pixel_format) {
        ESP_LOGW(TAG, "Requested pixel format 0x%08lx not supported, got 0x%08lx", 
                 config.pixel_format, fmt.fmt.pix.pixelformat);
    }

    // Set the requested format if different from current
    if (fmt.fmt.pix.pixelformat != config.pixel_format ||
        fmt.fmt.pix.width != config.width ||
        fmt.fmt.pix.height != config.height) {

        fmt.fmt.pix.pixelformat = config.pixel_format;
        fmt.fmt.pix.width = config.width;
        fmt.fmt.pix.height = config.height;

        if (ioctl(video_fd_, VIDIOC_S_FMT, &fmt) < 0) {
            ESP_LOGE(TAG, "Failed to set video format: %s", strerror(errno));
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }

        // Update stored values after setting
        sensor_format_ = fmt.fmt.pix.pixelformat;
        sensor_width_ = fmt.fmt.pix.width;
        sensor_height_ = fmt.fmt.pix.height;
    }

    // Request buffers for streaming
    struct v4l2_requestbuffers req = {};
    req.count = 4;
    req.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    req.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_REQBUFS, &req) < 0) {
        ESP_LOGE(TAG, "Failed to request video buffers: %s", strerror(errno));
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    if (req.count < 2) {
        ESP_LOGE(TAG, "Insufficient buffer memory for video capture");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    // Map the buffers
    for (int i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QUERYBUF, &buf) < 0) {
            ESP_LOGE(TAG, "Failed to query buffer %d: %s", i, strerror(errno));
            // Cleanup already mapped buffers
            for (int j = 0; j < i; j++) {
                munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
            }
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }

        mmap_buffers_[i].start = mmap(NULL, buf.length, PROT_READ | PROT_WRITE, MAP_SHARED, video_fd_, buf.m.offset);
        if (mmap_buffers_[i].start == MAP_FAILED) {
            ESP_LOGE(TAG, "Failed to map buffer %d: %s", i, strerror(errno));
            // Cleanup already mapped buffers
            for (int j = 0; j < i; j++) {
                munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
            }
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }
        mmap_buffers_[i].length = buf.length;

        // Queue the buffer
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) < 0) {
            ESP_LOGE(TAG, "Failed to queue buffer %d: %s", i, strerror(errno));
            munmap(mmap_buffers_[i].start, mmap_buffers_[i].length);
            // Cleanup already mapped buffers
            for (int j = 0; j < i; j++) {
                munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
            }
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }
    }

    // Start streaming
    int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(video_fd_, VIDIOC_STREAMON, &type) < 0) {
        ESP_LOGE(TAG, "Failed to start streaming: %s", strerror(errno));
        // Cleanup buffers
        for (int i = 0; i < req.count; i++) {
            munmap(mmap_buffers_[i].start, mmap_buffers_[i].length);
        }
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    streaming_on_ = true;
}

