bool Esp32Camera::Capture() {
    if (video_fd_ < 0 || !streaming_on_) {
        ESP_LOGE(TAG, "Camera not initialized or streaming off");
        return false;
    }

    // Wait for any previous encoding task to complete
    if (encoder_thread_.joinable()) {
        encoder_thread_.join();
    }

    // Dequeue a buffer from the camera
    struct v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0) {
        ESP_LOGE(TAG, "VIDIOC_DQBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    // Check if we have valid buffer data
    if (buf.index >= mmap_buffers_.size() || !mmap_buffers_[buf.index].start) {
        ESP_LOGE(TAG, "Invalid buffer index or start address");
        // Requeue the buffer before returning
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed during error recovery");
        }
        return false;
    }

    // Calculate frame size based on pixel format
    size_t frame_size = 0;
    uint16_t width = frame_.width;
    uint16_t height = frame_.height;

    // Determine frame size based on format
    switch (sensor_format_) {
        case V4L2_PIX_FMT_YUV422P:
        case V4L2_PIX_FMT_YUYV:
            frame_size = width * height * 2;  // YUV422: 2 bytes per pixel
            break;
        case V4L2_PIX_FMT_RGB565:
            frame_size = width * height * 2;  // RGB565: 2 bytes per pixel
            break;
        case V4L2_PIX_FMT_RGB24:
            frame_size = width * height * 3;  // RGB24: 3 bytes per pixel
            break;
        case V4L2_PIX_FMT_GREY:
            frame_size = width * height;      // GREY: 1 byte per pixel
            break;
        default:
            frame_size = width * height * 2;  // Default fallback
            break;
    }

    // Allocate memory for the frame, preferring PSRAM
    void* new_frame_data = nullptr;
    if (frame_size > 0) {
        // Try to allocate in PSRAM first
        new_frame_data = heap_caps_malloc(frame_size, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
        if (new_frame_data == nullptr) {
            // Fallback to normal RAM
            new_frame_data = malloc(frame_size);
        }

        if (new_frame_data == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate memory for frame (%zu bytes)", frame_size);
            // Requeue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
                ESP_LOGE(TAG, "VIDIOC_QBUF failed during error recovery");
            }
            return false;
        }
    }

    // Copy frame data from mmap buffer to our allocated buffer
    if (new_frame_data && mmap_buffers_[buf.index].start) {
        memcpy(new_frame_data, mmap_buffers_[buf.index].start, MIN(buf.bytesused, frame_size));
    }

    // Free existing frame data if any
    if (frame_.data) {
        heap_caps_free(frame_.data);
    }

    // Update frame metadata
    frame_.data = static_cast<uint8_t*>(new_frame_data);
    frame_.len = buf.bytesused;
    frame_.width = width;
    frame_.height = height;
    frame_.format = sensor_format_;

    // Requeue the buffer back to the camera
    if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
        ESP_LOGE(TAG, "VIDIOC_QBUF failed");
        return false;
    }

    return true;
}

