    std::queue<std::vector<uint8_t>> jpeg_chunks;
    std::mutex chunk_mutex;
    std::condition_variable chunk_cv;
    bool encoding_complete = false;
    std::string error_message = "";

    // Start JPEG encoding in a separate thread
    encoder_thread_ = std::thread([this, &jpeg_chunks, &chunk_mutex, &chunk_cv, &encoding_complete, &error_message]() {
