            if (result != ESP_OK) {
                error_message = "JPEG encoding failed";
                heap_caps_free(jpeg_buffer);
                encoding_complete = true;
                chunk_cv.notify_all();
                return;
            }

            // Split JPEG data into chunks for HTTP upload
            const size_t chunk_size = 4096; // 4KB chunks
            size_t offset = 0;

            while (offset < jpeg_size) {
                size_t current_chunk_size = std::min(chunk_size, jpeg_size - offset);
                std::vector<uint8_t> chunk(current_chunk_size);
                memcpy(chunk.data(), jpeg_buffer + offset, current_chunk_size);

