void WifiBoard::StartWifiConfigMode()
{
    ESP_LOGI(TAG, "Starting Wi-Fi configuration mode");

    // Set device state to configuring mode
    auto &wifi_manager = WifiManager::GetInstance();

    // Start Wi-Fi in configuration mode
    wifi_manager.StartConfigMode();

    // Provide user feedback
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_ENTERED);

    // Enable provisioning method based on compile-time flags
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Start BLE provisioning
    ESP_LOGI(TAG, "Starting BLE provisioning via Blufi");
    Blufi::GetInstance().init();
#elif defined(CONFIG_USE_WIFI_HOTSPOT_PROVISIONING)
    // Start hotspot provisioning - already handled by WifiManager::StartConfigMode()
    ESP_LOGI(TAG, "Starting hotspot provisioning");
#elif defined(CONFIG_USE_AUDIO_WIFI_PROVISIONING)
    // Start audio provisioning
    ESP_LOGI(TAG, "Starting audio provisioning");
    // Initialize audio input processing for AFSK demodulation
    AfskDemod::GetInstance().start();
#endif

    // Show configuration instructions to user
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_INSTRUCTIONS);
}

