void WifiBoard::EnterWifiConfigMode() {
    // Validate the current device state to ensure it's safe to enter Wi-Fi configuration mode
    if (in_config_mode_) {
        ESP_LOGI(TAG, "Already in Wi-Fi configuration mode");
        return;
    }

    // Gracefully shut down active audio and communication processes
    auto& app = Application::GetInstance();
    auto& board = Board::GetInstance();

    // Stop any ongoing audio processing
    auto codec = board.GetAudioCodec();
    if (codec) {
