    app.Alert(Lang::Strings::WIFI_CONFIG_MODE, 
              Lang::Strings::WIFI_CONFIG_MODE_HINT, 
              "gear", 
              Lang::Sounds::OGG_WIFICONFIG);

    // Reset network interfaces and prepare the system for new Wi-Fi settings
    // This will trigger the configuration mode entry
    StartWifiConfigMode();
}

