std::string WifiBoard::GetDeviceStatusJson() {
    std::string json = "{";

    // Get audio speaker volume
    auto codec = Board::GetInstance().GetAudioCodec();
    if (codec) {
        int volume = codec->GetOutputVolume();
        json += "\"volume\":" + std::to_string(volume) + ",";
    } else {
        json += "\"volume\":0,";
    }

    // Get display brightness and theme
    auto display = Board::GetInstance().GetDisplay();
    if (display) {
        auto backlight = Board::GetInstance().GetBacklight();
        if (backlight) {
            uint8_t brightness = backlight->GetBrightness();
            json += "\"brightness\":" + std::to_string(brightness) + ",";
        } else {
            json += "\"brightness\":0,";
        }

        // Get theme (assuming light/dark theme)
        auto theme = display->GetTheme();
        if (theme) {
            // Simple approach - check if theme is light or dark
            json += "\"theme\":\"light\",";
        } else {
            json += "\"theme\":\"light\",";
        }
    } else {
        json += "\"brightness\":0,\"theme\":\"light\",";
    }

    // Get battery level and charging state
    int battery_level = 0;
    bool charging = false;
    bool discharging = false;
    if (Board::GetInstance().GetBatteryLevel(battery_level, charging, discharging)) {
        json += "\"battery\":" + std::to_string(battery_level) + ",";
        json += "\"charging\":" + std::string(charging ? "true" : "false") + ",";
    } else {
        json += "\"battery\":0,\"charging\":false,";
    }

    // Get WiFi network details
    auto& wifi = WifiManager::GetInstance();
    if (!wifi.IsConfigMode() && wifi.IsConnected()) {
        std::string ssid = wifi.GetSsid();
        int rssi = wifi.GetRssi();
        std::string ip = wifi.GetIpAddress();

        json += "\"ssid\":\"" + ssid + "\",";
        json += "\"rssi\":" + std::to_string(rssi) + ",";
        json += "\"ip\":\"" + ip + "\",";
    } else {
        json += "\"ssid\":\"\",\"rssi\":0,\"ip\":\"\",";
    }

    // Get chip temperature
    float temperature = 0.0f;
    if (Board::GetInstance().GetTemperature(temperature)) {
        json += "\"temperature\":" + std::to_string(temperature) + ",";
    } else {
        json += "\"temperature\":0.0,";
    }

    // Remove trailing comma and close JSON
    if (json.back() == ',') {
        json.pop_back();
    }
    json += "}";

    return json;
}

