void LcdDisplay::SetEmotion(const char *emotion)
{
    DisplayLockGuard lock(this);

    // Handle null emotion case
    if (emotion == nullptr) {
        // Hide any existing emotion display
        if (emoji_image_ != nullptr) {
            lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
        }
        if (emoji_label_ != nullptr) {
            lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
        }
        return;
    }

    // Check if we're using WeChat-style messaging
#if CONFIG_USE_WECHAT_MESSAGE_STYLE
    // If emotion is "neutral" and WeChat-style messaging is enabled, hide the emotion display
    if (strcmp(emotion, "neutral") == 0) {
        Settings settings("display", false);
        bool wechat_style = settings.GetBool("wechat_style", false);
        if (wechat_style) {
            if (emoji_image_ != nullptr) {
                lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
            }
            if (emoji_label_ != nullptr) {
                lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
            }
            return;
        }
    }
#endif

    // Determine if the emotion is a static image or animated GIF
    bool is_gif = (strstr(emotion, ".gif") != nullptr);

    // Handle different emotion types
    if (is_gif) {
        // Handle animated GIF
        if (gif_controller_ == nullptr) {
            gif_controller_ = std::make_unique<GifController>();
        }

        // Stop any existing GIF playback
        gif_controller_->Stop();

        // Load and start the GIF animation
        if (gif_controller_->LoadGif(emotion)) {
            // Set up the GIF controller to render to our emoji image
            if (emoji_image_ != nullptr) {
                gif_controller_->SetTargetImage(emoji_image_);
                gif_controller_->Start();

                // Show the emoji image
                lv_obj_remove_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
                lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
            }
        }
    } else {
        // Handle static image or emoji character
        // First, stop any ongoing GIF animation
        if (gif_controller_) {
            gif_controller_->Stop();
        }

        // Check if this is a special emoji character
        if (strlen(emotion) == 1 && emotion[0] >= 0x20 && emotion[0] <= 0x7E) {
            // This appears to be a simple character, treat as emoji character
            if (emoji_label_ != nullptr) {
                lv_label_set_text(emoji_label_, emotion);
                lv_obj_remove_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
                if (emoji_image_ != nullptr) {
                    lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
                }
            }
        } else {
            // Treat as image asset path
            // Try to load the image
            std::unique_ptr<LvglImage> image = std::make_unique<LvglImage>(emotion);
            if (image->image_dsc() != nullptr) {
                // Successfully loaded image
                if (emoji_image_ != nullptr) {
                    // Set the image source
                    lv_image_set_src(emoji_image_, image->image_dsc());
                    lv_obj_remove_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
                    lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);

                    // Position the image properly
                    lv_obj_align(emoji_image_, LV_ALIGN_TOP_MID, 0, 0);
                }
            } else {
                // Failed to load image, fallback to showing emoji label with default icon
                if (emoji_label_ != nullptr) {
                    lv_label_set_text(emoji_label_, FONT_AWESOME_SMILE);
                    lv_obj_remove_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
                    if (emoji_image_ != nullptr) {
                        lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
                    }
                }
            }
        }
    }
}

