SingleLed::SingleLed(gpio_num_t gpio) {
    // Configure GPIO pin for RMT output
    gpio_config_t gpio_conf = {
        .pin_bit_mask = 1ULL << gpio,
        .mode = GPIO_MODE_OUTPUT,
        .pull_up_en = GPIO_PULLUP_DISABLE,
        .pull_down_en = GPIO_PULLDOWN_DISABLE,
        .intr_type = GPIO_INTR_DISABLE,
    };
    gpio_config(&gpio_conf);

    // Initialize LED strip with RMT peripheral for WS2812
    led_strip_config_t strip_config = LED_STRIP_RMT_DEFAULT_CONFIG(1, RMT_CHANNEL_0);
    led_strip_rmt_config_t rmt_config = {
        .clk_src = RMT_CLK_SRC_APB,
        .resolution_hz = 10 * 1000 * 1000, // 10MHz resolution
        .flags.with_dma = false,
    };

    esp_err_t ret = led_strip_new_rmt_ws2812(&strip_config, &rmt_config, &led_strip_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create LED strip: %s", esp_err_to_name(ret));
        return;
    }

    // Clear the LED initially (turn it off)
    led_strip_clear(led_strip_);

    // Create blink timer
    const esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .name = "led_blink",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
    };

    ret = esp_timer_create(&timer_args, &blink_timer_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create blink timer: %s", esp_err_to_name(ret));
        return;
    }
}

