bool MqttProtocol::OpenAudioChannel()
{
    ESP_LOGI(TAG, "Opening audio channel");

    // Ensure we're connected to MQTT
    if (!mqtt_ || !mqtt_->IsConnected())
    {
        ESP_LOGE(TAG, "MQTT client not connected");
        SetError(Lang::Strings::SERVER_NOT_CONNECTED);
        return false;
    }

    // Send hello message to request audio channel
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message))
    {
        ESP_LOGE(TAG, "Failed to send hello message");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Wait for server hello response with timeout
    TickType_t timeout_ticks = pdMS_TO_TICKS(5000); // 5 second timeout
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_, 
                                          MQTT_PROTOCOL_SERVER_HELLO_EVENT, 
                                          pdTRUE,  // Clear bits on exit
                                          pdFALSE, // Wait for any bit
                                          timeout_ticks);

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT))
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    // Create UDP socket for audio data
    {
        std::lock_guard<std::mutex> lock(channel_mutex_);

        auto network = Board::GetInstance().GetNetwork();
        udp_ = network->CreateUdp(0);

        if (!udp_)
        {
            ESP_LOGE(TAG, "Failed to create UDP socket");
            SetError(Lang::Strings::NETWORK_ERROR);
            return false;
        }

        // Connect to UDP server
        struct sockaddr_in addr;
        memset(&addr, 0, sizeof(addr));
        addr.sin_family = AF_INET;
        addr.sin_port = htons(udp_port_);
        inet_pton(AF_INET, udp_server_.c_str(), &addr.sin_addr);

        if (udp_->Connect((struct sockaddr*)&addr, sizeof(addr)) < 0)
        {
            ESP_LOGE(TAG, "Failed to connect UDP socket");
            udp_.reset();
            SetError(Lang::Strings::NETWORK_ERROR);
            return false;
        }

        // Set up UDP receive callback
        udp_->OnData([this](const std::string& data)
        {
            if (data.size() < 16) // Minimum header size
            {
                ESP_LOGW(TAG, "Received too small UDP packet");
                return;
            }

            // Decrypt the packet
            std::string nonce(data.substr(0, 16));
            std::string encrypted_data = data.substr(16);

            // Validate sequence number
            uint32_t sequence = ntohl(*(uint32_t*)&nonce[12]);
            if (sequence <= remote_sequence_)
            {
                ESP_LOGW(TAG, "Invalid packet sequence: %u (expected > %u)", sequence, remote_sequence_);
                return;
            }
            remote_sequence_ = sequence;

            // Decrypt data
            std::string decrypted;
            decrypted.resize(encrypted_data.size());
            size_t nc_off = 0;
            uint8_t stream_block[16] = {0};

            if (mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_data.size(), &nc_off, 
                                      (uint8_t*)nonce.data(), stream_block,
                                      (uint8_t*)encrypted_data.data(), 
                                      (uint8_t*)decrypted.data()) != 0)
            {
                ESP_LOGE(TAG, "Failed to decrypt audio data");
                return;
            }

            // Parse binary protocol header
            if (decrypted.size() < sizeof(BinaryProtocol3))
            {
                ESP_LOGW(TAG, "Decrypted data too small for binary protocol");
                return;
            }

            BinaryProtocol3* header = (BinaryProtocol3*)decrypted.data();
            if (header->type != 0) // Only handle OPUS packets (type 0)
            {
                ESP_LOGW(TAG, "Unexpected packet type: %d", header->type);
                return;
            }

            if (header->payload_size > decrypted.size() - sizeof(BinaryProtocol3))
            {
                ESP_LOGW(TAG, "Payload size mismatch");
                return;
            }

            // Create audio packet
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->sample_rate = server_sample_rate_;
            packet->frame_duration = server_frame_duration_;
            packet->timestamp = ntohl(*(uint32_t*)&nonce[8]);
            packet->payload.assign(decrypted.begin() + sizeof(BinaryProtocol3), 
                                 decrypted.begin() + sizeof(BinaryProtocol3) + header->payload_size);

            // Forward to callback
            if (on_incoming_audio_ != nullptr)
            {
                on_incoming_audio_(std::move(packet));
            }
        });
    }

    // Notify that audio channel is opened
    if (on_audio_channel_opened_ != nullptr)
    {
        on_audio_channel_opened_();
    }

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

