void MqttProtocol::ParseServerHello(const cJSON *root)
{
    // Extract UDP transport configuration
    cJSON *transport = cJSON_GetObjectItem(root, "transport");
    if (transport && cJSON_IsString(transport)) {
        if (strcmp(transport->valuestring, "udp") != 0) {
            ESP_LOGE(TAG, "Unsupported transport type: %s", transport->valuestring);
            return;
        }
    }

    // Extract server address and port
    cJSON *server = cJSON_GetObjectItem(root, "server");
    if (server && cJSON_IsString(server)) {
        std::string server_addr = server->valuestring;
        size_t colon_pos = server_addr.find(':');
        if (colon_pos != std::string::npos) {
            udp_server_ = server_addr.substr(0, colon_pos);
            udp_port_ = std::stoi(server_addr.substr(colon_pos + 1));
        } else {
            udp_server_ = server_addr;
            udp_port_ = 8883; // Default port
        }
    }

    // Extract encryption key and nonce
    cJSON *key_item = cJSON_GetObjectItem(root, "key");
    if (key_item && cJSON_IsString(key_item)) {
        std::string key_str = key_item->valuestring;
        std::string key = DecodeHexString(key_str);
        if (key.size() == 16) { // AES-128 key
            memcpy(aes_key_, key.data(), key.size());
        }
    }

    cJSON *nonce_item = cJSON_GetObjectItem(root, "nonce");
    if (nonce_item && cJSON_IsString(nonce_item)) {
        std::string nonce_str = nonce_item->valuestring;
        std::string nonce = DecodeHexString(nonce_str);
        if (nonce.size() == 16) {
            memcpy(aes_nonce_, nonce.data(), nonce.size());
        }
    }

    // Extract audio parameters
    cJSON *audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (audio_params && cJSON_IsObject(audio_params)) {
        cJSON *sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (sample_rate && cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valueint;
        }

        cJSON *frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (frame_duration && cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
        }
    }

    // Initialize AES context
    mbedtls_aes_init(&aes_ctx_);
    if (mbedtls_aes_setkey_enc(&aes_ctx_, aes_key_, 128) != 0) {
        ESP_LOGE(TAG, "Failed to set AES encryption key");
        return;
    }

    // Set session ID
    cJSON *session_id = cJSON_GetObjectItem(root, "session_id");
    if (session_id && cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
    }

    // Signal that server hello was processed successfully
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

