bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Check WebSocket connection status before transmitting audio data
    if (websocket_ == nullptr || !websocket_->IsConnected()) {
        return false;
    }

    // Determine the negotiated protocol version
    int version = version_;

    // Format the audio packet with appropriate headers and metadata based on protocol version
    std::vector<uint8_t> buffer;

    if (version == 2) {
        // Version 2 binary protocol
        BinaryProtocol2 bp2;
        bp2.version = htons(2);
        bp2.type = htons(0); // OPUS type
        bp2.reserved = 0;
        bp2.timestamp = htonl(packet->timestamp);
        bp2.payload_size = htonl(packet->payload.size());

        // Calculate total buffer size
        size_t total_size = sizeof(BinaryProtocol2) + packet->payload.size();
        buffer.resize(total_size);

        // Copy header
        memcpy(buffer.data(), &bp2, sizeof(BinaryProtocol2));
        // Copy payload
        memcpy(buffer.data() + sizeof(BinaryProtocol2), packet->payload.data(), packet->payload.size());
    }
    else if (version == 3) {
        // Version 3 binary protocol
        BinaryProtocol3 bp3;
        bp3.type = 0; // OPUS type
        bp3.reserved = 0;
        bp3.payload_size = htons(packet->payload.size());

        // Calculate total buffer size
        size_t total_size = sizeof(BinaryProtocol3) + packet->payload.size();
        buffer.resize(total_size);

        // Copy header
        memcpy(buffer.data(), &bp3, sizeof(BinaryProtocol3));
        // Copy payload
        memcpy(buffer.data() + sizeof(BinaryProtocol3), packet->payload.data(), packet->payload.size());
    }
    else {
        // Raw payload format (default case)
        buffer = std::move(packet->payload);
    }

    // Transmit the formatted audio data over the WebSocket connection
    if (!websocket_->Send(reinterpret_cast<const char*>(buffer.data()), buffer.size(), true)) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

