bool WebsocketProtocol::OpenAudioChannel() {
    // Check if websocket is already open
    if (websocket_ && websocket_->IsConnected()) {
        return true;
    }

    // Create new websocket instance
    websocket_ = std::make_unique<WebSocket>();

    // Setup WebSocket connection parameters
    WebSocket::ConnectOptions options;
    options.url = "wss://your-server-url/audio"; // This should be configurable

    // Add authentication headers
    options.headers["Authorization"] = "Bearer " + GetAuthToken(); // Assuming GetAuthToken() exists
    options.headers["device-id"] = GetDeviceId(); // Assuming GetDeviceId() exists
    options.headers["device-model"] = GetDeviceModel(); // Assuming GetDeviceModel() exists

    // Set protocol version
    options.headers["protocol-version"] = std::to_string(version_);

    // Set up binary data handler
    websocket_->OnBinaryData([this](const uint8_t* data, size_t length) {
        if (length < sizeof(BinaryProtocol2) && length < sizeof(BinaryProtocol3)) {
            ESP_LOGW(TAG, "Received binary data too small");
            return;
        }

        // Handle different protocol versions
        if (version_ == 2) {
            if (length < sizeof(BinaryProtocol2)) {
                ESP_LOGW(TAG, "Invalid binary protocol v2 packet");
                return;
            }

            auto bp2 = (const BinaryProtocol2*)data;
            uint16_t version = ntohs(bp2->version);
            uint32_t timestamp = ntohl(bp2->timestamp);
            uint32_t payload_size = ntohl(bp2->payload_size);

            // Validate packet
            if (length < sizeof(BinaryProtocol2) + payload_size) {
                ESP_LOGW(TAG, "Binary protocol v2 packet size mismatch");
                return;
            }

            // Extract payload
            std::vector<uint8_t> payload(bp2->payload, bp2->payload + payload_size);

            // Create packet and dispatch
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = timestamp;
            packet->payload = std::move(payload);
            packet->sample_rate = server_sample_rate_;
            packet->frame_duration = server_frame_duration_;

            if (on_incoming_audio_) {
                on_incoming_audio_(std::move(packet));
            }
        } else if (version_ == 3) {
            if (length < sizeof(BinaryProtocol3)) {
                ESP_LOGW(TAG, "Invalid binary protocol v3 packet");
                return;
            }

            auto bp3 = (const BinaryProtocol3*)data;
            uint16_t payload_size = ntohs(bp3->payload_size);

            // Validate packet
            if (length < sizeof(BinaryProtocol3) + payload_size) {
                ESP_LOGW(TAG, "Binary protocol v3 packet size mismatch");
                return;
            }

            // Extract payload
            std::vector<uint8_t> payload(bp3->payload, bp3->payload + payload_size);

            // Create packet and dispatch
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = 0; // No timestamp in v3
            packet->payload = std::move(payload);
            packet->sample_rate = server_sample_rate_;
            packet->frame_duration = server_frame_duration_;

            if (on_incoming_audio_) {
                on_incoming_audio_(std::move(packet));
            }
        } else {
            // Raw data handling for other versions
            std::vector<uint8_t> payload(data, data + length);
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = 0;
            packet->payload = std::move(payload);
            packet->sample_rate = server_sample_rate_;
            packet->frame_duration = server_frame_duration_;

            if (on_incoming_audio_) {
                on_incoming_audio_(std::move(packet));
            }
        }
    });

    // Set up text message handler
    websocket_->OnTextMessage([this](const std::string& message) {
        cJSON* root = cJSON_Parse(message.c_str());
        if (root == nullptr) {
            ESP_LOGW(TAG, "Failed to parse JSON message");
            return;
        }

        if (on_incoming_json_) {
            on_incoming_json_(root);
        }

        cJSON_Delete(root);
    });

    // Connect to WebSocket
    if (!websocket_->Connect(options)) {
        ESP_LOGE(TAG, "Failed to connect to WebSocket");
        websocket_.reset();
        return false;
    }

    // Send hello message after connection
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        websocket_.reset();
        return false;
    }

    // Wait for server hello response
    if (xEventGroupWaitBits(event_group_handle_, 
                           WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT, 
                           pdTRUE, pdFALSE, pdMS_TO_TICKS(5000)) == 0) {
        ESP_LOGE(TAG, "Timeout waiting for server hello");
        websocket_.reset();
        return false;
    }

    // Set up connection callbacks
    websocket_->OnConnected([this]() {
        if (on_connected_) {
            on_connected_();
        }
    });

    websocket_->OnDisconnected([this]() {
        if (on_disconnected_) {
            on_disconnected_();
        }
    });

    return true;
}

