std::string WebsocketProtocol::GetHelloMessage() {
    // Create JSON object for the hello message
    cJSON* root = cJSON_CreateObject();

    // Set message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add protocol version
    cJSON_AddNumberToObject(root, "protocol_version", version_);

    // Add supported features
    cJSON* features = cJSON_CreateArray();
    cJSON_AddItemToArray(features, cJSON_CreateString("aec"));
    cJSON_AddItemToArray(features, cJSON_CreateString("mcp"));
    cJSON_AddItemToObject(root, "features", features);

    // Add transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio parameters
    cJSON* audio_params = cJSON_CreateObject();

    // Get audio configuration from system
    Settings settings("audio", false);
    int sample_rate = settings.GetInt("sample_rate", 16000);
    int channels = settings.GetInt("channels", 1);
    int frame_duration = settings.GetInt("frame_duration", 20);
    std::string format = settings.GetString("format", "pcm");

    cJSON_AddNumberToObject(audio_params, "sample_rate", sample_rate);
    cJSON_AddNumberToObject(audio_params, "channels", channels);
    cJSON_AddNumberToObject(audio_params, "frame_duration", frame_duration);
    cJSON_AddStringToObject(audio_params, "format", format.c_str());

    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Convert to string
    char* json_string = cJSON_Print(root);
    std::string result = json_string;

    // Clean up
    free(json_string);
    cJSON_Delete(root);

    return result;
}

